1	import { spawn } from "node:child_process";
2	import type { AgentBackend, AgentRequest, AgentResponse } from "./types.js";
3	
4	// CliAgentBackend — the gap-closer + superset vs the raw engine.
5	// In Claude Code's dynamic workflows the subagent IS a full Claude Code agent. Here the basic
6	// unit is ALSO a full coding agent — but a *pluggable* one: dispatch each agent() call to any
7	// real agent CLI (claude, ccz/ccd/ccq, codex/cx, cursor, …) as a child process. The agent brings
8	// its own tools (Bash/files/MCP), so this reproduces "subagent = full agent" faithfully and goes
9	// beyond raw by being vendor- and model-agnostic.
10	//
11	// Security: processes are spawned with an args ARRAY (no shell), so the prompt cannot break out.
12	
13	export interface CliAgentInvocation {
14	  cmd: string;
15	  args: string[];
16	  /** Optional stdin payload (some agents read the prompt from stdin). */
17	  input?: string;
18	}
19	
20	export interface CliAgentSpec {
21	  /** Build the process invocation from the request. */
22	  buildCommand: (req: AgentRequest) => CliAgentInvocation;
23	  /** Parse stdout into the result. Default: trimmed text, or extracted JSON when a schema is set. */
24	  parseOutput?: (stdout: string, req: AgentRequest) => unknown;
25	  /** Working directory (string, or per-request — e.g. a git worktree for isolation). */
26	  cwd?: string | ((req: AgentRequest) => string | undefined);
27	  env?: NodeJS.ProcessEnv;
28	  /** Kill the agent after this many ms. Default 300000 (5 min). */
29	  timeoutMs?: number;
30	}
31	
32	const estTokens = (s: string): number => Math.ceil(s.length / 4);
33	
34	/** Best-effort JSON extraction from an agent's free-form stdout (whole / fenced / first balanced). */
35	export function extractJson(text: string): unknown {
36	  try {
37	    return JSON.parse(text);
38	  } catch {
39	    /* fall through */
40	  }
41	  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
42	  if (fence && fence[1]) {
43	    try {
44	      return JSON.parse(fence[1].trim());
45	    } catch {
46	      /* fall through */
47	    }
48	  }
49	  const start = text.search(/[{[]/);
50	  if (start >= 0) {
51	    for (let end = text.length; end > start; end--) {
52	      try {
53	        return JSON.parse(text.slice(start, end));
54	      } catch {
55	        /* keep shrinking */
56	      }
57	    }
58	  }
59	  return undefined;
60	}
61	
62	function defaultParse(stdout: string, req: AgentRequest): unknown {
63	  const text = stdout.trim();
64	  if (req.schema === undefined) return text;
65	  const obj = extractJson(text);
66	  return obj ?? text;
67	}
