69	interface SpawnResult {
70	  stdout: string;
71	  stderr: string;
72	  code: number | null;
73	}
74	
75	export class CliAgentBackend implements AgentBackend {
76	  constructor(private readonly spec: CliAgentSpec) {}
77	
78	  async run(req: AgentRequest): Promise<AgentResponse> {
79	    const { cmd, args, input } = this.spec.buildCommand(req);
80	    const specCwd = typeof this.spec.cwd === "function" ? this.spec.cwd(req) : this.spec.cwd;
81	    // Honor an engine-provided cwd (e.g. a worktree from opts.isolation:'worktree').
82	    const cwd = specCwd ?? req.cwd;
83	    const { stdout } = await this._spawn(cmd, args, input, cwd);
84	    const output = (this.spec.parseOutput ?? defaultParse)(stdout, req);
85	    // CLI agents rarely report token usage; estimate deterministically from text size.
86	    return { output, inputTokens: estTokens(req.prompt), outputTokens: estTokens(stdout) };
87	  }
88	
89	  private _spawn(cmd: string, args: string[], input: string | undefined, cwd: string | undefined): Promise<SpawnResult> {
90	    const timeoutMs = this.spec.timeoutMs ?? 300_000;
91	    return new Promise<SpawnResult>((resolve, reject) => {
92	      const child = spawn(cmd, args, {
93	        cwd,
94	        env: this.spec.env ?? process.env,
95	        stdio: ["pipe", "pipe", "pipe"],
96	      });
97	      let stdout = "";
98	      let stderr = "";
99	      const timer = setTimeout(() => {
100	        child.kill("SIGKILL");
101	        reject(new Error(`agent '${cmd}' timed out after ${timeoutMs}ms`));
102	      }, timeoutMs);
103	
104	      child.stdout.on("data", (d: Buffer) => (stdout += d.toString()));
105	      child.stderr.on("data", (d: Buffer) => (stderr += d.toString()));
106	      child.on("error", (e) => {
107	        clearTimeout(timer);
108	        reject(e);
109	      });
110	      child.on("close", (code) => {
111	        clearTimeout(timer);
112	        if (code === 0 || stdout.trim().length > 0) {
113	          resolve({ stdout, stderr, code });
114	        } else {
115	          reject(new Error(`agent '${cmd}' exited ${code}: ${stderr.slice(0, 500)}`));
116	        }
117	      });
118	
119	      if (input !== undefined) child.stdin.write(input);
120	      child.stdin.end();
121	    });
122	  }
123	
124	  // ---------- presets for agent CLIs (flags verified on this host via --help) ----------
125	
126	  /** Claude Code headless: `claude -p "<prompt>" [--model M] --output-format text [--bare]`.
127	   *  Flags verified against official docs (code.claude.com/docs/en/cli-reference). `bare:true`
128	   *  adds `--bare` (skip hooks/MCP/skills/CLAUDE.md) — recommended for clean scripted/CI runs. */
129	  static claude(o?: { model?: string; bare?: boolean; extraArgs?: string[]; timeoutMs?: number; cwd?: string }): CliAgentBackend {
130	    return new CliAgentBackend({
131	      buildCommand: (req) => {
132	        const model = req.model ?? o?.model;
133	        return {
134	          cmd: "claude",
135	          args: [
136	            "-p",
137	            req.prompt,
138	            ...(model ? ["--model", model] : []),
139	            "--output-format",
140	            "text",
141	            ...(o?.bare ? ["--bare"] : []),
142	            ...(o?.extraArgs ?? []),
143	          ],
144	        };
145	      },
146	      ...(o?.cwd !== undefined ? { cwd: o.cwd } : {}),
147	      timeoutMs: o?.timeoutMs ?? 300_000,
148	    });
149	  }
150	
151	  /** Free Claude-Code-compatible worker wrappers (ccz/ccd/ccq), per the orchestration playbook
152	   *  (`ccz -p --dangerously-skip-permissions "<prompt>"`). Use only for low-risk worker tasks. */
153	  static worker(bin: "ccz" | "ccd" | "ccq", o?: { model?: string; timeoutMs?: number; cwd?: string }): CliAgentBackend {
154	    return new CliAgentBackend({
155	      buildCommand: (req) => {
156	        const model = req.model ?? o?.model;
157	        return {
158	          cmd: bin,
159	          args: ["-p", "--dangerously-skip-permissions", req.prompt, ...(model ? ["--model", model] : [])],
160	        };
161	      },
162	      ...(o?.cwd !== undefined ? { cwd: o.cwd } : {}),
163	      timeoutMs: o?.timeoutMs ?? 300_000,
164	    });
165	  }
166	
167	  /** OpenAI Codex CLI (flags verified against developers.openai.com/codex/cli/reference):
168	   *  `codex exec --sandbox <s> --ask-for-approval never [--model M] [--output-schema <json>] "<prompt>"`.
169	   *  The final agent message prints to stdout (progress goes to stderr). */
170	  static codex(o?: {
171	    model?: string;
172	    sandbox?: "read-only" | "workspace-write" | "danger-full-access";
173	    timeoutMs?: number;
174	    cwd?: string;
175	  }): CliAgentBackend {
176	    return new CliAgentBackend({
177	      buildCommand: (req) => {
178	        const model = req.model ?? o?.model;
179	        return {
180	          cmd: "codex",
181	          args: [
182	            "exec",
183	            "--sandbox",
184	            o?.sandbox ?? "workspace-write",
185	            "--ask-for-approval",
186	            "never",
187	            ...(model ? ["--model", model] : []),
188	            ...(req.schema ? ["--output-schema", JSON.stringify(req.schema)] : []),
189	            req.prompt,
190	          ],
191	        };
192	      },
193	      ...(o?.cwd !== undefined ? { cwd: o.cwd } : {}),
194	      timeoutMs: o?.timeoutMs ?? 300_000,
195	    });
196	  }
197	
198	  /** OpenCode (sst) headless: `opencode run "<prompt>" [-m provider/model] [--agent A] [--pure]`
199	   *  — prints the response to stdout. Flags verified via `opencode --help`. `model` is
200	   *  `provider/model` form (e.g. `anthropic/claude-sonnet-4-6`); `pure:true` adds `--pure`
201	   *  (no external plugins, e.g. skip oh-my-opencode config for clean CI). */
202	  static opencode(o?: { model?: string; agent?: string; pure?: boolean; timeoutMs?: number; cwd?: string }): CliAgentBackend {
203	    return new CliAgentBackend({
204	      buildCommand: (req) => {
205	        const model = req.model ?? o?.model;
206	        return {
207	          cmd: "opencode",
208	          args: [
209	            "run",
210	            req.prompt,
211	            ...(model ? ["--model", model] : []),
212	            ...(o?.agent ? ["--agent", o.agent] : []),
213	            ...(o?.pure ? ["--pure"] : []),
214	          ],
215	        };
216	      },
217	      ...(o?.cwd !== undefined ? { cwd: o.cwd } : {}),
218	      timeoutMs: o?.timeoutMs ?? 300_000,
219	    });
220	  }
221	
222	  /** Any other agent CLI (cx/cursor/local) — supply your own buildCommand. */
223	  static custom(spec: CliAgentSpec): CliAgentBackend {
224	    return new CliAgentBackend(spec);
225	  }
226	}
